class SAMLResponseParser:
    """Parses and validates SAML responses from the Identity Provider."""

    def __init__(self, saml_response_b64):
        self.raw_response = base64.b64decode(saml_response_b64)
        self.xml_string = self.raw_response.decode('utf-8')
        self.root = ET.fromstring(self.xml_string)
        self.errors = []
        self.attributes = {}
        self.name_id = None
        self.session_index = None
        self.issuer = None
        self.assertion = None

    def validate_response(self):
        """Validate the SAML response structure and status."""
        # Check response status
        status_code_elem = self.root.find(
            './/samlp:Status/samlp:StatusCode', SAML_NAMESPACES
        )
        if status_code_elem is None:
            self.errors.append('Missing StatusCode element in SAML response')
            return False

        status_value = status_code_elem.get('Value', '')
        if status_value != 'urn:oasis:names:tc:SAML:2.0:status:Success':
            status_message_elem = self.root.find(
                './/samlp:Status/samlp:StatusMessage', SAML_NAMESPACES
            )
            message = status_message_elem.text if status_message_elem is not None else 'Unknown error'
            self.errors.append(f'SAML authentication failed: {status_value} - {message}')
            return False

        # Check for Assertion
        self.assertion = self.root.find('.//saml:Assertion', SAML_NAMESPACES)
        if self.assertion is None:
            self.errors.append('No Assertion element found in SAML response')
            return False

        # Validate Issuer
        issuer_elem = self.assertion.find('saml:Issuer', SAML_NAMESPACES)
        if issuer_elem is None:
            self.errors.append('Missing Issuer in Assertion')
            return False
        self.issuer = issuer_elem.text
        if self.issuer != SAML_CONFIG['idp_entity_id']:
            self.errors.append(
                f'Issuer mismatch: expected {SAML_CONFIG["idp_entity_id"]}, got {self.issuer}'
            )
            return False

        # Validate response destination
        destination = self.root.get('Destination', '')
        if destination and destination != SAML_CONFIG['sp_acs_url']:
            self.errors.append(
                f'Destination mismatch: expected {SAML_CONFIG["sp_acs_url"]}, got {destination}'
            )
            return False

        # Validate conditions
        if not self._validate_conditions():
            return False

        # Validate Subject Confirmation
        if not self._validate_subject_confirmation():
            return False

        return True

    def _validate_conditions(self):
        """Validate assertion conditions including time validity and audience."""
        conditions = self.assertion.find('saml:Conditions', SAML_NAMESPACES)
        if conditions is None:
            self.errors.append('Missing Conditions element in Assertion')
            return False

        now = datetime.utcnow()

        not_before = conditions.get('NotBefore')
        if not_before:
            not_before_dt = self._parse_saml_datetime(not_before)
            if not_before_dt and now < not_before_dt - timedelta(minutes=5):
                self.errors.append(f'Assertion not yet valid. NotBefore: {not_before}')
                return False

        not_on_or_after = conditions.get('NotOnOrAfter')
        if not_on_or_after:
            not_on_or_after_dt = self._parse_saml_datetime(not_on_or_after)
            if not_on_or_after_dt and now >= not_on_or_after_dt + timedelta(minutes=5):
                self.errors.append(f'Assertion has expired. NotOnOrAfter: {not_on_or_after}')
                return False

        # Validate audience restriction
        audience_restriction = conditions.find(
            'saml:AudienceRestriction', SAML_NAMESPACES
        )
        if audience_restriction is not None:
            audiences = audience_restriction.findall('saml:Audience', SAML_NAMESPACES)
            audience_values = [a.text for a in audiences if a.text]
            if SAML_CONFIG['sp_entity_id'] not in audience_values:
                self.errors.append(
                    f'SP entity ID {SAML_CONFIG["sp_entity_id"]} not in audience list: {audience_values}'
                )
                return False

        return True

    def _validate_subject_confirmation(self):
        """Validate the Subject and SubjectConfirmation elements."""
        subject = self.assertion.find('saml:Subject', SAML_NAMESPACES)
        if subject is None:
            self.errors.append('Missing Subject element in Assertion')
            return False

        # Extract NameID
        name_id_elem = subject.find('saml:NameID', SAML_NAMESPACES)
        if name_id_elem is not None:
            self.name_id = name_id_elem.text
        else:
            self.errors.append('Missing NameID in Subject')
            return False

        # Validate SubjectConfirmation
        subject_confirmation = subject.find(
            'saml:SubjectConfirmation', SAML_NAMESPACES
        )
        if subject_confirmation is not None:
            method = subject_confirmation.get('Method', '')
            if method != 'urn:oasis:names:tc:SAML:2.0:cm:bearer':
                self.errors.append(f'Unsupported SubjectConfirmation Method: {method}')
                return False

            confirmation_data = subject_confirmation.find(
                'saml:SubjectConfirmationData', SAML_NAMESPACES
            )
            if confirmation_data is not None:
                recipient = confirmation_data.get('Recipient', '')
                if recipient and recipient != SAML_CONFIG['sp_acs_url']:
                    self.errors.append(
                        f'Recipient mismatch: expected {SAML_CONFIG["sp_acs_url"]}, got {recipient}'
                    )
                    return False

                not_on_or_after = confirmation_data.get('NotOnOrAfter')
                if not_on_or_after:
                    expiry = self._parse_saml_datetime(not_on_or_after)
                    if expiry and datetime.utcnow() >= expiry:
                        self.errors.append('SubjectConfirmationData has expired')
                        return False

        return True

    def extract_attributes(self):
        """Extract user attributes from the SAML Assertion's AttributeStatement."""
        if self.assertion is None:
            return {}

        attribute_statement = self.assertion.find(
            'saml:AttributeStatement', SAML_NAMESPACES
        )
        if attribute_statement is None:
            return {}

        attributes = {}
        for attribute in attribute_statement.findall('saml:Attribute', SAML_NAMESPACES):
            attr_name = attribute.get('Name', '')
            attr_friendly_name = attribute.get('FriendlyName', '')

            values = []
            for attr_value in attribute.findall('saml:AttributeValue', SAML_NAMESPACES):
                if attr_value.text:
                    values.append(attr_value.text)

            # Use friendly name as key if available, otherwise use full name
            key = attr_friendly_name if attr_friendly_name else attr_name

            # Store single values as strings, multiple as lists
            if len(values) == 1:
                attributes[key] = values[0]
            elif len(values) > 1:
                attributes[key] = values

            # Also store by full OID/URI name for reference
            if attr_friendly_name and attr_name != attr_friendly_name:
                if len(values) == 1:
                    attributes[attr_name] = values[0]
                elif len(values) > 1:
                    attributes[attr_name] = values

        self.attributes = attributes

        # Extract session index from AuthnStatement
        authn_statement = self.assertion.find(
            'saml:AuthnStatement', SAML_NAMESPACES
        )
        if authn_statement is not None:
            self.session_index = authn_statement.get('SessionIndex')

        return attributes

    def get_user_info(self):
        """Return a consolidated user info dictionary."""
        attrs = self.attributes

        # Common SAML attribute mappings
        user_info = {
            'name_id': self.name_id,
            'session_index': self.session_index,
            'issuer': self.issuer,
            'email': (
                attrs.get('email')
                or attrs.get('mail')
                or attrs.get('http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress')
                or attrs.get('urn:oid:0.9.2342.19200300.100.1.3')
                or self.name_id
            ),
            'first_name': (
                attrs.get('firstName')
                or attrs.get('givenName')
                or attrs.get('http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname')
                or attrs.get('urn:oid:2.5.4.42')
                or ''
            ),
            'last_name': (
                attrs.get('lastName')
                or attrs.get('sn')
                or attrs.get('surname')
                or attrs.get('http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname')
                or attrs.get('urn:oid:2.5.4.4')
                or ''
            ),
            'display_name': (
                attrs.get('displayName')
                or attrs.get('cn')
                or attrs.get('http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name')
                or ''
            ),
            'groups': (
                attrs.get('groups')
                or attrs.get('memberOf')
                or attrs.get('http://schemas.xmlsoap.org/claims/Group')
                or []
            ),
            'roles': (
                attrs.get('roles')
                or attrs.get('role')
                or attrs.get('http://schemas.microsoft.com/ws/2008/06/identity/claims/role')
                or []
            ),
            'department': attrs.get('department', ''),
            'title': attrs.get('title', ''),
            'phone': attrs.get('telephoneNumber', ''),
            'raw_attributes': attrs,
        }

        # Ensure groups and roles are lists
        for field in ['groups', 'roles']:
            if isinstance(user_info[field], str):
                user_info[field] = [user_info[field]]

        # Build display name if not provided
        if not user_info['display_name'] and (user_info['first_name'] or user_info['last_name']):
            user_info['display_name'] = f"{user_info['first_name']} {user_info['last_name']}".strip()

        return user_info

    @staticmethod
    def _parse_saml_datetime(dt_string):
        """Parse a SAML datetime string."""
        try:
            # Handle format: 2024-01-15T10:30:00Z
            dt_string = dt_string.rstrip('Z')
            if '.' in dt_string:
                return datetime.strptime(dt_string, '%Y-%m-%dT%H:%M:%S.%f')
            return datetime.strptime(dt_string, '%Y-%m-%dT%H:%M:%S')
        except ValueError:
            return None


def create_authn_request():
    """Generate a SAML AuthnRequest XML."""
    request_id = f'_{"".join(str(uuid.uuid4()).split("-"))}'
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')

    authn_request = f'''<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{SAML_CONFIG['idp_sso_url']}"
    AssertionConsumerServiceURL="{SAML_CONFIG['sp_acs_url']}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{SAML_CONFIG['sp_entity_id']}</saml:Issuer>
    <samlp:NameIDPolicy
        Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
    <samlp:RequestedAuthnContext Comparison="exact">
        <saml:AuthnContextClassRef>
            urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport
        </saml:AuthnContextClassRef>
    </samlp:RequestedAuthnContext>
</samlp:AuthnRequest>'''

    return request_id, authn_request


def create_logout_request(name_id, session_index):
    """Generate a SAML LogoutRequest XML."""
    request_id = f'_{"".join(str(uuid.uuid4()).split("-"))}'
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')

    logout_request = f'''<samlp:LogoutRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{SAML_CONFIG['idp_slo_url']}">
    <saml:Issuer>{SAML_CONFIG['sp_entity_id']}</saml:Issuer>
    <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">{name_id}</saml:NameID>
    <samlp:SessionIndex>{session_index}</samlp:SessionIndex>
</samlp:LogoutRequest>'''

    return request_id, logout_request


def login_required(f):
    """Decorator to protect routes that require authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            session['relay_state'] = request.url
            return redirect(url_for('saml_login'))
        return f(*args, **kwargs)
    return decorated_function


def role_required(*roles):
    """Decorator to enforce role-based access control."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            if 'user' not in session:
                session['relay_state'] = request.url
                return redirect(url_for('saml_login'))
            user_roles = session.get('user', {}).get('roles', [])
            if not any(role in user_roles for role in roles):
                return jsonify({'error': 'Insufficient permissions'}), 403
            return f(*args, **kwargs)
        return decorated_function
    return decorator


