@app.route('/saml/login')
def saml_login():
    """Initiate SAML SSO by redirecting to the IdP."""
    request_id, authn_request_xml = create_authn_request()

    # Store request ID for response validation
    session['saml_request_id'] = request_id

    # Preserve the original URL the user wanted to visit
    relay_state = session.pop('relay_state', url_for('index'))

    # Base64 encode the AuthnRequest
    encoded_request = base64.b64encode(authn_request_xml.encode('utf-8')).decode('utf-8')

    # For HTTP-POST binding, render a form that auto-submits
    return render_template_string('''
    <!DOCTYPE html>
    <html>
    <head><title>Redirecting to Identity Provider...</title></head>
    <body onload="document.forms[0].submit();">
        <h3>Redirecting to Identity Provider...</h3>
        <p>If you are not redirected automatically, please click the button below.</p>
        <form method="POST" action="{{ idp_url }}">
            <input type="hidden" name="SAMLRequest" value="{{ saml_request }}" />
            <input type="hidden" name="RelayState" value="{{ relay_state }}" />
            <button type="submit">Continue to SSO</button>
        </form>
    </body>
    </html>
    ''', idp_url=SAML_CONFIG['idp_sso_url'],
         saml_request=encoded_request,
         relay_state=relay_state)


@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    """Assertion Consumer Service - processes SAML responses from the IdP."""
    saml_response_b64 = request.form.get('SAMLResponse')
    relay_state = request.form.get('RelayState', url_for('index'))

    if not saml_response_b64:
        return jsonify({'error': 'No SAMLResponse found in the request'}), 400

    try:
        # Parse the SAML response
        parser = SAMLResponseParser(saml_response_b64)

        # Validate the response
        if not parser.validate_response():
            app.logger.error(f'SAML validation errors: {parser.errors}')
            return render_template_string('''
            <!DOCTYPE html>
            <html>
            <head><title>SSO Error</title>
            <style>body { font-family: Arial; max-width: 600px; margin: 50px auto; }
                   .error { background: #ffe0e0; padding: 20px; border-radius: 8px; }
                   .btn { display: inline-block; padding: 10px 20px; background: #0066cc;
                          color: white; text-decoration: none; border-radius: 4px; }</style>
            </head>
            <body>
                <h1>Authentication Error</h1>
                <div class="error">
                    <h3>SAML validation failed:</h3>
                    <ul>
                    {% for error in errors %}
                        <li>{{ error }}</li>
                    {% endfor %}
                    </ul>
                </div>
                <br>
                <a href="/saml/login" class="btn">Try Again</a>
            </body>
            </html>
            ''', errors=parser.errors), 403

        # Extract attributes and build user info
        parser.extract_attributes()
        user_info = parser.get_user_info()

        # Validate InResponseTo if we stored the original request ID
        response_in_response_to = parser.root.get('InResponseTo', '')
        stored_request_id = session.pop('saml_request_id', None)
        if stored_request_id and response_in_response_to:
            if response_in_response_to != stored_request_id:
                app.logger.warning(
                    f'InResponseTo mismatch: expected {stored_request_id}, '
                    f'got {response_in_response_to}'
                )
                return jsonify({'error': 'SAML response InResponseTo mismatch'}), 403

        # Create user session
        session.permanent = True
        session['user'] = user_info
        session['authenticated'] = True
        session['auth_time'] = datetime.utcnow().isoformat()

        # Store in server-side session store
        session_key = str(uuid.uuid4())
        session['session_key'] = session_key
        user_sessions[session_key] = {
            'user_info': user_info,
            'created_at': datetime.utcnow(),
            'name_id': user_info['name_id'],
            'session_index': user_info['session_index'],
        }

        app.logger.info(
            f'User authenticated via SAML SSO: {user_info["email"]} '
            f'(NameID: {user_info["name_id"]})'
        )

        return redirect(relay_state)

    except ET.ParseError as e:
        app.logger.error(f'Failed to parse SAML XML: {e}')
        return jsonify({'error': 'Invalid SAML response XML'}), 400
    except Exception as e:
        app.logger.error(f'SAML processing error: {e}', exc_info=True)
        return jsonify({'error': 'Internal error processing SAML response'}), 500


@app.route('/saml/logout')
def saml_logout():
    """Initiate SAML Single Logout."""
    user = session.get('user', {})
    name_id = user.get('name_id', '')
    session_index = user.get('session_index', '')

    # Clean up server-side session
    session_key = session.get('session_key')
    if session_key and session_key in user_sessions:
        del user_sessions[session_key]

    # Clear Flask session
    session.clear()

    if name_id and session_index:
        # Create LogoutRequest and redirect to IdP
        request_id, logout_request_xml = create_logout_request(name_id, session_index)
        encoded_request = base64.b64encode(logout_request_xml.encode('utf-8')).decode('utf-8')

        return render_template_string('''
        <!DOCTYPE html>
        <html>
        <head><title>Logging out...</title></head>
        <body onload="document.forms[0].submit();">
            <h3>Logging out...</h3>
            <form method="POST" action="{{ idp_url }}">
                <input type="hidden" name="SAMLRequest" value="{{ saml_request }}" />
                <input type="hidden" name="RelayState" value="{{ relay_state }}" />
                <button type="submit">Continue</button>
            </form>
        </body>
        </html>
        ''', idp_url=SAML_CONFIG['idp_slo_url'],
             saml_request=encoded_request,
             relay_state=url_for('index', _external=True))

    return redirect(url_for('index'))


@app.route('/saml/slo', methods=['POST', 'GET'])
def saml_slo():
    """Handle Single Logout response from IdP or IdP-initiated logout."""
    # If POST with SAMLResponse, the IdP is confirming our logout request
    if request.method == 'POST' and request.form.get('SAMLResponse'):
        # Logout confirmed by IdP
        session.clear()
        return redirect(url_for('index'))

    # If POST with SAMLRequest, the IdP is requesting we log out the user
    if request.method == 'POST' and request.form.get('SAMLRequest'):
        saml_request_b64 = request.form.get('SAMLRequest')
        try:
            xml_bytes = base64.b64decode(saml_request_b64)
            root = ET.fromstring(xml_bytes.decode('utf-8'))

            name_id_elem = root.find('.//saml:NameID', SAML_NAMESPACES)
            if name_id_elem is not None:
                name_id = name_id_elem.text
                # Find and remove the user's session
                keys_to_remove = [
                    k for k, v in user_sessions.items()
                    if v.get('name_id') == name_id
                ]
                for key in keys_to_remove:
                    del user_sessions[key]

            session.clear()

            # Send LogoutResponse back to IdP
            response_id = f'_{"".join(str(uuid.uuid4()).split("-"))}'
            issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
            in_response_to = root.get('ID', '')

            logout_response = f'''<samlp:LogoutResponse
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{response_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{SAML_CONFIG['idp_slo_url']}"
    InResponseTo="{in_response_to}">
    <saml:Issuer>{SAML_CONFIG['sp_entity_id']}</saml:Issuer>
    <samlp:Status>
        <samlp:StatusCode Value="urn:oasis:names:tc:SAML:2.0:status:Success"/>
    </samlp:Status>
</samlp:LogoutResponse>'''

            encoded_response = base64.b64encode(
                logout_response.encode('utf-8')
            ).decode('utf-8')

            relay_state = request.form.get('RelayState', '')

            return render_template_string('''
            <!DOCTYPE html>
            <html>
            <body onload="document.forms[0].submit();">
                <form method="POST" action="{{ idp_url }}">
                    <input type="hidden" name="SAMLResponse" value="{{ saml_response }}" />
                    {% if relay_state %}
                    <input type="hidden" name="RelayState" value="{{ relay_state }}" />
                    {% endif %}
                </form>
            </body>
            </html>
            ''', idp_url=SAML_CONFIG['idp_slo_url'],
                 saml_response=encoded_response,
                 relay_state=relay_state)

        except Exception as e:
            app.logger.error(f'SLO processing error: {e}')
            session.clear()
            return redirect(url_for('index'))

    return redirect(url_for('index'))


@app.route('/saml/metadata')
def saml_metadata():
    """Serve the SP metadata XML for IdP configuration."""
    metadata = f'''<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor
    xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
    entityID="{SAML_CONFIG['sp_entity_id']}">
    <md:SPSSODescriptor
        AuthnRequestsSigned="false"
        WantAssertionsSigned="true"
        protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">

        <md:SingleLogoutService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{SAML_CONFIG['sp_slo_url']}"/>

        <md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:persistent</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:transient</md:NameIDFormat>

        <md:AssertionConsumerService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{SAML_CONFIG['sp_acs_url']}"
            index="0"
            isDefault="true"/>

    </md:SPSSODescriptor>

    <md:Organization>
        <md:OrganizationName xml:lang="en">My Enterprise App</md:OrganizationName>
        <md:OrganizationDisplayName xml:lang="en">My Enterprise Application</md:OrganizationDisplayName>
        <md:OrganizationURL xml:lang="en">https://myapp.example.com</md:OrganizationURL>
    </md:Organization>

    <md:ContactPerson contactType="technical">
        <md:GivenName>IT Support</md:GivenName>
        <md:EmailAddress>it-support@example.com</md:EmailAddress>
    </md:ContactPerson>
</md:EntityDescriptor>'''

    return app.response_class(metadata, mimetype='application/xml')


