@app.route('/test/generate-saml-response')
def generate_test_saml_response():
    """
    Generate a test SAML response for development/testing purposes.
    DO NOT use in production.
    """
    if not app.debug:
        return jsonify({'error': 'Only available in debug mode'}), 403

    now = datetime.utcnow()
    not_before = (now - timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')
    not_on_or_after = (now + timedelta(minutes=30)).strftime('%Y-%m-%dT%H:%M:%SZ')
    issue_instant = now.strftime('%Y-%m-%dT%H:%M:%SZ')
    authn_instant = now.strftime('%Y-%m-%dT%H:%M:%SZ')
    response_id = f'_{"".join(str(uuid.uuid4()).split("-"))}'
    assertion_id = f'_{"".join(str(uuid.uuid4()).split("-"))}'
    session_index = f'_{"".join(str(uuid.uuid4()).split("-"))}'

    saml_response = f'''<samlp:Response
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{response_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{SAML_CONFIG['sp_acs_url']}">
    <saml:Issuer>{SAML_CONFIG['idp_entity_id']}</saml:Issuer>
    <samlp:Status>
        <samlp:StatusCode Value="urn:oasis:names:tc:SAML:2.0:status:Success"/>
    </samlp:Status>
    <saml:Assertion ID="{assertion_id}" Version="2.0" IssueInstant="{issue_instant}">
        <saml:Issuer>{SAML_CONFIG['idp_entity_id']}</saml:Issuer>
        <saml:Subject>
            <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">john.doe@example.com</saml:NameID>
            <saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer">
                <saml:SubjectConfirmationData
                    NotOnOrAfter="{not_on_or_after}"
                    Recipient="{SAML_CONFIG['sp_acs_url']}"/>
            </saml:SubjectConfirmation>
        </saml:Subject>
        <saml:Conditions NotBefore="{not_before}" NotOnOrAfter="{not_on_or_after}">
            <saml:AudienceRestriction>
                <saml:Audience>{SAML_CONFIG['sp_entity_id']}</saml:Audience>
            </saml:AudienceRestriction>
        </saml:Conditions>
        <saml:AuthnStatement AuthnInstant="{authn_instant}" SessionIndex="{session_index}">
            <saml:AuthnContext>
                <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</saml:AuthnContextClassRef>
            </saml:AuthnContext>
        </saml:AuthnStatement>
        <saml:AttributeStatement>
            <saml:Attribute Name="email" FriendlyName="email">
                <saml:AttributeValue>john.doe@example.com</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="firstName" FriendlyName="firstName">
                <saml:AttributeValue>John</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="lastName" FriendlyName="lastName">
                <saml:AttributeValue>Doe</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="displayName" FriendlyName="displayName">
                <saml:AttributeValue>John Doe</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="department" FriendlyName="department">
                <saml:AttributeValue>Engineering</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="title" FriendlyName="title">
                <saml:AttributeValue>Senior Developer</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="groups" FriendlyName="groups">
                <saml:AttributeValue>engineering</saml:AttributeValue>
                <saml:AttributeValue>developers</saml:AttributeValue>
                <saml:AttributeValue>all-staff</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="roles" FriendlyName="roles">
                <saml:AttributeValue>admin</saml:AttributeValue>
                <saml:AttributeValue>user</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="telephoneNumber" FriendlyName="telephoneNumber">
                <saml:AttributeValue>+1-555-0123</saml:AttributeValue>
            </saml:Attribute>
        </saml:AttributeStatement>
    </saml:Assertion>
</samlp:Response>'''

    encoded = base64.b64encode(saml_response.encode('utf-8')).decode('utf-8')

    return render_template_string('''
    <!DOCTYPE html>
    <html>
    <head><title>Test SAML Response</title>
    <style>body { font-family: Arial; max-width: 800px; margin: 50px auto; padding: 20px; }
           textarea { width: 100%; height: 200px; font-family: monospace; font-size: 12px; }
           .btn { display: inline-block; padding: 10px 20px; background: #0066cc;
                  color: white; border: none; border-radius: 4px; cursor: pointer; font-size: 16px; }</style>
    </head>
    <body>
        <h1>Test SAML Response Generator</h1>
        <p>This simulates an IdP posting a SAML response to our ACS endpoint.</p>
        <h3>Encoded SAML Response:</h3>
        <textarea readonly>{{ encoded }}</textarea>
        <br><br>
        <form method="POST" action="/saml/acs">
            <input type="hidden" name="SAMLRequest" value="" />
            <input type="hidden" name="SAMLResponse" value="{{ encoded }}" />
            <input type="hidden" name="RelayState" value="/" />
            <button type="submit" class="btn">Submit Test SAML Response to ACS</button>
        </form>
    </body>
    </html>
    ''', encoded=encoded)


